   Instruction *Res = nullptr;
   // Get the basic block this bundle is in. All instructions in the bundle
   // should be in this block (except for extractelement-like instructions with
-  // constant indices or gathered loads or copyables).
-  auto *Front = E->getMainOp();
-  auto *BB = Front->getParent();
+  // constant indices or gathered loads or copyables). For entries with invalid
+  // S, we cannot use getMainOp().
+  Instruction *Front = nullptr;
+  BasicBlock *BB = nullptr;
+  if (E->S) {
+    Front = E->getMainOp();
+    BB = Front->getParent();
+  } else {
+    // This should only happen for gather entries. Find any instruction.
+    Front = cast<Instruction>(*find_if(E->Scalars, IsaPred<Instruction>));
+    BB = Front->getParent();
+  }
   assert(((GatheredLoadsEntriesFirst.has_value() &&
            E->getOpcode() == Instruction::Load && E->isGather() &&
            E->Idx < *GatheredLoadsEntriesFirst) ||
